@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="_context" IsFixed="false">
        <QueryBuilderGroup Group="EffectiveQuery" Depth="0" Parent="null" />
    </CascadingValue>

    @if (ShowJsonPreview)
    {
        <div class="mt-4 rounded-md border border-border/40 bg-muted/30">
            <div class="border-b border-border/40 px-3 py-1.5 text-xs font-medium text-muted-foreground">JSON</div>
            <pre class="overflow-x-auto p-3 text-xs text-foreground"><code>@QueryBuilderSerialization.ToJson(EffectiveQuery)</code></pre>
        </div>
    }
</div>

@code {
    /// <summary>The fields the consumer can build conditions against. Required.</summary>
    [Parameter] public IReadOnlyList<QueryField> Fields { get; set; } = Array.Empty<QueryField>();

    /// <summary>The query tree. Two-way bindable via <c>@bind-Query</c>. When <c>null</c> on
    /// first render, an empty root group (And, no rules) is created.</summary>
    [Parameter] public QueryGroup? Query { get; set; }

    /// <summary>Raised whenever the query tree changes (rule/group added, removed, or edited). Also fires once on first render for an uncontrolled (initially-null) builder to publish the auto-seeded empty root group.</summary>
    [Parameter] public EventCallback<QueryGroup> QueryChanged { get; set; }

    /// <summary>When <c>true</c>, renders a read-only JSON view of the query below the builder.</summary>
    [Parameter] public bool ShowJsonPreview { get; set; }

    /// <summary>Maximum group nesting depth. The "Add group" button is disabled at this depth.</summary>
    [Parameter] public int MaxDepth { get; set; } = 5;

    /// <summary>When <c>false</c>, "Remove rule" / "Remove group" are hidden when it would leave
    /// a group empty (the root may always be empty).</summary>
    [Parameter] public bool AllowEmptyGroups { get; set; } = true;

    /// <summary>Optional override for how a rule's value editor renders. Receives the rule.
    /// When supplied, replaces the built-in per-type editor entirely (the consumer is then
    /// responsible for binding to <see cref="QueryRule.Value"/> and calling
    /// <c>NotifyChanged</c> via the cascaded context — see docs).</summary>
    [Parameter] public RenderFragment<QueryRule>? ValueEditorTemplate { get; set; }

    /// <summary>Additional CSS classes merged onto the root element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private QueryBuilderContext _context = default!;

    // The working query tree. We deliberately do NOT store uncontrolled state in the
    // [Parameter] Query: Blazor resets parameter values to the parent's supplied value
    // on every render, so an auto-seeded tree written back into Query would be wiped
    // (and re-created empty) whenever an unrelated parent re-render pushed null again.
    // The backing field survives those re-renders; we only adopt the parameter when the
    // consumer actually supplies a (changed) instance.
    private QueryGroup _query = QueryGroup.CreateEmpty();
    private QueryGroup? _lastSuppliedQuery;
    private bool _seededFired;

    private QueryGroup EffectiveQuery => _query;

    private string CssClass => Cx.Merge("w-full text-sm", Class);

    protected override void OnInitialized() => SyncQuery();

    protected override void OnParametersSet() => SyncQuery();

    private void SyncQuery()
    {
        // Adopt the parameter only when the consumer actually supplied one and it changed
        // (identity compare against the last value we accepted — never against the live
        // backing field, which our own callbacks mutate).
        if (Query is not null && !ReferenceEquals(Query, _lastSuppliedQuery))
        {
            _query = Query;
            _lastSuppliedQuery = Query;
            _seededFired = true; // a real instance is in play; no auto-seed needed
        }

        RebuildContext();
    }

    protected override async Task OnInitializedAsync()
    {
        // On the first render of an uncontrolled (Query == null) builder, publish the
        // auto-seeded instance so a two-way @bind-Query captures it instead of being
        // perpetually reset to null.
        if (!_seededFired && Query is null)
        {
            _seededFired = true;
            _lastSuppliedQuery = _query;
            await QueryChanged.InvokeAsync(_query);
        }
    }

    private void RebuildContext()
    {
        _context = new QueryBuilderContext(
            Fields,
            MaxDepth,
            AllowEmptyGroups,
            ValueEditorTemplate,
            NotifyChanged);
    }

    private async Task NotifyChanged()
    {
        await QueryChanged.InvokeAsync(EffectiveQuery);
        StateHasChanged();
    }

    // --- Static helpers (re-exported for convenience) ---

    /// <summary>Serializes a query tree to indented JSON (System.Text.Json, camelCase, string enums).</summary>
    public static string ToJson(QueryGroup query) => QueryBuilderSerialization.ToJson(query);

    /// <summary>Parses a query tree from JSON produced by <see cref="ToJson"/>. Returns <c>null</c> on failure.</summary>
    public static QueryGroup? FromJson(string json) => QueryBuilderSerialization.FromJson(json);

    /// <summary>Compiles a query tree to a LINQ predicate. Returns <c>null</c> for an empty tree.</summary>
    public static System.Linq.Expressions.Expression<Func<T, bool>>? ToExpression<
        [System.Diagnostics.CodeAnalysis.DynamicallyAccessedMembers(System.Diagnostics.CodeAnalysis.DynamicallyAccessedMemberTypes.PublicProperties | System.Diagnostics.CodeAnalysis.DynamicallyAccessedMemberTypes.NonPublicProperties)] T>(QueryGroup query)
        => QueryBuilderSerialization.ToExpression<T>(query);

    /// <summary>Cascaded state shared with the recursive <see cref="QueryBuilderGroup"/> renderer.</summary>
    public sealed record QueryBuilderContext(
        IReadOnlyList<QueryField> Fields,
        int MaxDepth,
        bool AllowEmptyGroups,
        RenderFragment<QueryRule>? ValueEditorTemplate,
        Func<Task> NotifyChanged)
    {
        public QueryField? FindField(string name) => Fields.FirstOrDefault(f => f.Name == name);
    }
}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject IComponentInteropService Interop

@{
    var isRoot = Depth == 0;
    var canNest = Depth < Ctx.MaxDepth;
}

<div class="@GroupClass" role="group" aria-label="@L[isRoot ? "QueryBuilder.QueryGroup" : "QueryBuilder.NestedQueryGroup"]" @attributes="AdditionalAttributes">
    <div class="flex flex-wrap items-center gap-2">
        <div class="inline-flex items-center rounded-md bg-muted p-0.5" role="radiogroup" aria-label="@L["QueryBuilder.Combinator"]">
            <button type="button"
                    id="@_andId"
                    role="radio"
                    aria-checked="@((Group.Combinator == QueryCombinator.And).ToString().ToLowerInvariant())"
                    tabindex="@(Group.Combinator == QueryCombinator.And ? 0 : -1)"
                    class="@CombinatorPillClass(Group.Combinator == QueryCombinator.And)"
                    @onclick="@(() => SetCombinator(QueryCombinator.And))"
                    @onkeydown="HandleCombinatorKeyDown">
                AND
            </button>
            <button type="button"
                    id="@_orId"
                    role="radio"
                    aria-checked="@((Group.Combinator == QueryCombinator.Or).ToString().ToLowerInvariant())"
                    tabindex="@(Group.Combinator == QueryCombinator.Or ? 0 : -1)"
                    class="@CombinatorPillClass(Group.Combinator == QueryCombinator.Or)"
                    @onclick="@(() => SetCombinator(QueryCombinator.Or))"
                    @onkeydown="HandleCombinatorKeyDown">
                OR
            </button>
        </div>

        <Button Variant="Button.ButtonVariant.Outline" Size="Button.ButtonSize.Sm"
                OnClick="AddRule" aria-label="@L["QueryBuilder.AddRule"]">
            <SvgGlyph Svg="@(LumeoIcons.Plus)" class="h-3.5 w-3.5" />
            <span>Rule</span>
        </Button>

        <Button Variant="Button.ButtonVariant.Outline" Size="Button.ButtonSize.Sm"
                OnClick="AddGroup" Disabled="@(!canNest)" aria-label="@L["QueryBuilder.AddGroup"]">
            <SvgGlyph Svg="@(LumeoIcons.FolderPlus)" class="h-3.5 w-3.5" />
            <span>Group</span>
        </Button>

        <div class="ms-auto"></div>

        @if (!isRoot && CanRemoveSelf)
        {
            <Button Variant="Button.ButtonVariant.Ghost" Size="Button.ButtonSize.Icon"
                    OnClick="RemoveSelf" Class="h-7 w-7 text-muted-foreground hover:text-destructive"
                    aria-label="@L["QueryBuilder.RemoveGroup"]">
                <SvgGlyph Svg="@(LumeoIcons.X)" class="h-4 w-4" />
            </Button>
        }
    </div>

    @if (Group.Rules.Count == 0)
    {
        <p class="px-1 py-2 text-xs text-muted-foreground">No conditions yet. Add a rule or a group.</p>
    }
    else
    {
        <div class="space-y-2">
            @foreach (var node in Group.Rules.ToList())
            {
                @if (node is QueryRule rule)
                {
                    var field = string.IsNullOrEmpty(rule.Field) ? null : Ctx.FindField(rule.Field);
                    // A non-empty field that resolves to nothing is "unknown" ONLY once the
                    // field list is actually populated — an empty Ctx.Fields means "not yet
                    // loaded", which must not be mistaken for "field removed".
                    var isUnknownField = field is null
                        && !string.IsNullOrEmpty(rule.Field)
                        && Ctx.Fields.Count > 0;
                    <div class="flex flex-wrap items-center gap-2 rounded-md border border-border/40 bg-card p-2">
                        @* Field picker *@
                        <select class="@SelectClass" value="@rule.Field" @onchange="@(e => OnFieldChanged(rule, e.Value?.ToString()))" aria-label="@L["QueryBuilder.Field"]">
                            @if (string.IsNullOrEmpty(rule.Field))
                            {
                                <option value="" disabled selected>Select field…</option>
                            }
                            @if (isUnknownField)
                            {
                                @* Surface the stored-but-unknown field so the dropdown shows the
                                   real value instead of silently snapping to the first option. *@
                                <option value="@rule.Field" disabled selected>@rule.Field</option>
                            }
                            @foreach (var f in Ctx.Fields)
                            {
                                <option value="@f.Name" selected="@(f.Name == rule.Field)">@f.DisplayLabel</option>
                            }
                        </select>

                        @if (isUnknownField)
                        {
                            <span class="inline-flex items-center gap-1 text-xs text-destructive" role="alert" aria-label="@L["QueryBuilder.UnknownField"]">
                                <SvgGlyph Svg="@(LumeoIcons.TriangleAlert)" class="h-3.5 w-3.5" />
                                <span>@L["QueryBuilder.UnknownField"]</span>
                            </span>
                        }
                        @if (field is not null)
                        {
                            @* Operator picker *@
                            <select class="@SelectClass" value="@rule.Operator" @onchange="@(e => OnOperatorChanged(rule, e.Value?.ToString()))" aria-label="@L["QueryBuilder.Operator"]">
                                @foreach (var op in field.EffectiveOperators)
                                {
                                    <option value="@op" selected="@(op == rule.Operator)">@QueryBuilderOperators.LabelFor(op)</option>
                                }
                            </select>

                            @* Value editor *@
                            @if (Ctx.ValueEditorTemplate is not null)
                            {
                                @Ctx.ValueEditorTemplate(rule)
                            }
                            else if (rule.Operator is "in" or "notIn")
                            {
                                @RenderMultiValueEditor(field, rule)
                            }
                            else if (!QueryBuilderOperators.NoValueOperators.Contains(rule.Operator))
                            {
                                @RenderValueEditor(field, rule, isSecond: false)
                                @if (QueryBuilderOperators.RangeOperators.Contains(rule.Operator))
                                {
                                    <span class="text-xs text-muted-foreground">and</span>
                                    @RenderValueEditor(field, rule, isSecond: true)
                                }
                            }
                        }

                        <div class="ms-auto"></div>

                        @if (CanRemoveChild)
                        {
                            <Button Variant="Button.ButtonVariant.Ghost" Size="Button.ButtonSize.Icon"
                                    OnClick="@(() => RemoveNode(rule))" Class="h-7 w-7 text-muted-foreground hover:text-destructive"
                                    aria-label="@L["QueryBuilder.RemoveRule"]">
                                <SvgGlyph Svg="@(LumeoIcons.X)" class="h-4 w-4" />
                            </Button>
                        }
                    </div>
                }
                else if (node is QueryGroup childGroup)
                {
                    <QueryBuilderGroup Group="childGroup" Depth="@(Depth + 1)" Parent="Group" />
                }
            }
        </div>
    }
</div>

@code {
    [CascadingParameter] public QueryBuilder.QueryBuilderContext Ctx { get; set; } = default!;

    /// <summary>The group node this instance renders — its combinator, rules, and nested groups.</summary>
    [Parameter, EditorRequired] public QueryGroup Group { get; set; } = default!;

    /// <summary>Nesting depth of this group (0 for the root). Drives the visual indent and gates "Add group" against <see cref="QueryBuilder.QueryBuilderContext.MaxDepth"/>.</summary>
    [Parameter] public int Depth { get; set; }

    /// <summary>The parent group (null for the root) — used to support self-removal.</summary>
    [Parameter] public QueryGroup? Parent { get; set; }

    /// <summary>Additional CSS classes merged onto the root group element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root group element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Stable per-instance ids for the two combinator radios so arrow-key navigation
    // can move DOM focus to the newly-selected radio via Interop.FocusElement.
    private readonly string _andId = LumeoIds.New("qb-comb-and");
    private readonly string _orId = LumeoIds.New("qb-comb-or");

    private bool AllowEmpty => Ctx.AllowEmptyGroups;

    // Removing a child is allowed when empties are permitted, or when more than one child remains.
    private bool CanRemoveChild => AllowEmpty || Group.Rules.Count > 1;

    // Removing this (non-root) group is allowed when empties are permitted in the parent,
    // or when the parent would still have at least one child afterwards.
    private bool CanRemoveSelf => Parent is not null && (AllowEmpty || Parent.Rules.Count > 1);

    private const string GroupBase = "rounded-lg p-3 space-y-3";

    private string GroupClass => Depth == 0
        ? Cx.Merge(GroupBase, "border border-border/40 bg-card", Class)
        : Cx.Merge(GroupBase, "border-s-2 border-border/40 bg-muted/30 ps-4", Class);

    private const string SelectClass =
        "h-8 rounded-md border border-input bg-background px-2 text-sm text-foreground outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50";

    private const string InputClass =
        "h-8 w-40 rounded-md border border-input bg-background px-2 text-sm text-foreground outline-none placeholder:text-muted-foreground focus-visible:ring-[1.5px] focus-visible:ring-ring";

    private static string CombinatorPillClass(bool active) => active
        ? "inline-flex items-center justify-center rounded-md bg-primary px-2.5 py-1 text-xs font-semibold text-primary-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
        : "inline-flex items-center justify-center rounded-md px-2.5 py-1 text-xs font-medium text-muted-foreground hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1";

    private async Task SetCombinator(QueryCombinator c)
    {
        if (Group.Combinator == c) return;
        Group.Combinator = c;
        await Ctx.NotifyChanged();
    }

    private string CombinatorId(QueryCombinator c) => c == QueryCombinator.And ? _andId : _orId;

    // WAI-ARIA radio group keyboard support for the And/Or combinator pills.
    // Arrows (and Home/End) move selection AND roving focus to the target radio;
    // Space/Enter are left to the native <button> click (which already runs
    // SetCombinator), mirroring RadioGroupItem so we never double-fire.
    private async Task HandleCombinatorKeyDown(KeyboardEventArgs e)
    {
        var target = e.Key switch
        {
            // Two-option group: arrows toggle to the other; Home selects And, End selects Or.
            "ArrowDown" or "ArrowRight" or "ArrowUp" or "ArrowLeft" =>
                Group.Combinator == QueryCombinator.And ? QueryCombinator.Or : QueryCombinator.And,
            "Home" => QueryCombinator.And,
            "End" => QueryCombinator.Or,
            _ => (QueryCombinator?)null
        };
        if (target is null) return;

        await SetCombinator(target.Value);
        // Roving focus follows the selection (Interop.FocusElement is a no-op under
        // bUnit but recorded by the tracking interop so the move stays assertable).
        try
        {
            await Interop.FocusElement(CombinatorId(target.Value));
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    private bool _pdRegistered;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        // Suppress the browser's page-scroll on the arrow keys while a combinator
        // radio is focused — registered out-of-band (not @onkeydown:preventDefault,
        // which would also swallow Tab and trap keyboard users in the group).
        try
        {
            await Interop.RegisterPreventDefaultKeys(
                _andId,
                new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft", "Home", "End" }
                    .Select(k => new PreventDefaultKeyRule(k)).ToArray());
            await Interop.RegisterPreventDefaultKeys(
                _orId,
                new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft", "Home", "End" }
                    .Select(k => new PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_andId);
            await Interop.UnregisterPreventDefaultKeys(_orId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    private async Task AddRule()
    {
        var firstField = Ctx.Fields.FirstOrDefault();
        var rule = new QueryRule
        {
            Field = firstField?.Name ?? "",
            Operator = firstField?.EffectiveOperators.FirstOrDefault() ?? "",
            Value = DefaultValueFor(firstField)
        };
        Group.Rules.Add(rule);
        await Ctx.NotifyChanged();
    }

    private async Task AddGroup()
    {
        if (Depth >= Ctx.MaxDepth) return;
        Group.Rules.Add(QueryGroup.CreateEmpty());
        await Ctx.NotifyChanged();
    }

    private async Task RemoveNode(QueryNode node)
    {
        Group.Rules.Remove(node);
        await Ctx.NotifyChanged();
    }

    private async Task RemoveSelf()
    {
        if (Parent is null) return;
        Parent.Rules.Remove(Group);
        await Ctx.NotifyChanged();
    }

    private async Task OnFieldChanged(QueryRule rule, string? newField)
    {
        if (string.IsNullOrEmpty(newField) || rule.Field == newField) return;
        rule.Field = newField;
        var field = Ctx.FindField(newField);
        // Field type changed — reset operator to the field's first, clear value.
        rule.Operator = field?.EffectiveOperators.FirstOrDefault() ?? "";
        rule.Value = DefaultValueFor(field);
        rule.Value2 = null;
        await Ctx.NotifyChanged();
    }

    private static bool IsMultiValue(string op) => op is "in" or "notIn";

    private async Task OnOperatorChanged(QueryRule rule, string? newOp)
    {
        if (string.IsNullOrEmpty(newOp) || rule.Operator == newOp) return;
        var wasRange = QueryBuilderOperators.RangeOperators.Contains(rule.Operator);
        // Toggling between single-value and multi-value ("in"/"notIn") editors changes the
        // value shape (scalar vs comma-joined list), so clear a stale value on that transition.
        if (IsMultiValue(rule.Operator) != IsMultiValue(newOp)) rule.Value = null;
        rule.Operator = newOp;
        if (!QueryBuilderOperators.RangeOperators.Contains(newOp)) rule.Value2 = null;
        if (QueryBuilderOperators.NoValueOperators.Contains(newOp)) { rule.Value = null; rule.Value2 = null; }
        await Ctx.NotifyChanged();
    }

    private async Task SetValue(QueryRule rule, bool isSecond, object? value)
    {
        if (isSecond) rule.Value2 = value;
        else rule.Value = value;
        await Ctx.NotifyChanged();
    }

    private static object? DefaultValueFor(QueryField? field) => field?.Type switch
    {
        QueryFieldType.Boolean => false,
        _ => null
    };

    private static string? AsString(object? v) => v?.ToString();

    private RenderFragment RenderValueEditor(QueryField field, QueryRule rule, bool isSecond) => builder =>
    {
        var current = isSecond ? rule.Value2 : rule.Value;
        switch (field.Type)
        {
            case QueryFieldType.Number:
            {
                builder.OpenElement(0, "input");
                builder.AddAttribute(1, "type", "number");
                builder.AddAttribute(2, "class", InputClass + " w-28");
                builder.AddAttribute(3, "value", AsString(current));
                builder.AddAttribute(4, "aria-label", isSecond ? "Value (upper bound)" : "Value");
                builder.AddAttribute(5, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e =>
                        {
                            var raw = e.Value?.ToString();
                            object? parsed = double.TryParse(raw, System.Globalization.NumberStyles.Any,
                                System.Globalization.CultureInfo.InvariantCulture, out var d) ? d : raw;
                            await SetValue(rule, isSecond, parsed);
                        }));
                builder.CloseElement();
                break;
            }
            case QueryFieldType.Date:
            {
                builder.OpenElement(0, "input");
                builder.AddAttribute(1, "type", "date");
                builder.AddAttribute(2, "class", InputClass);
                builder.AddAttribute(3, "value", AsString(current));
                builder.AddAttribute(4, "aria-label", isSecond ? "Date (upper bound)" : "Date");
                builder.AddAttribute(5, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e => await SetValue(rule, isSecond, e.Value?.ToString())));
                builder.CloseElement();
                break;
            }
            case QueryFieldType.Boolean:
            {
                var isChecked = current is bool b && b;
                builder.OpenElement(0, "label");
                builder.AddAttribute(1, "class", "inline-flex items-center gap-1.5 text-sm text-foreground");
                builder.OpenElement(2, "input");
                builder.AddAttribute(3, "type", "checkbox");
                builder.AddAttribute(4, "class", "h-4 w-4 rounded border-input accent-primary");
                builder.AddAttribute(5, "checked", isChecked);
                builder.AddAttribute(6, "aria-label", "Value");
                builder.AddAttribute(7, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e => await SetValue(rule, isSecond, e.Value is bool bb && bb)));
                builder.CloseElement();
                builder.AddContent(8, isChecked ? "true" : "false");
                builder.CloseElement();
                break;
            }
            case QueryFieldType.Select:
            {
                builder.OpenElement(0, "select");
                builder.AddAttribute(1, "class", SelectClass);
                builder.AddAttribute(2, "value", AsString(current));
                builder.AddAttribute(3, "aria-label", "Value");
                builder.AddAttribute(4, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e => await SetValue(rule, isSecond, e.Value?.ToString())));
                if (string.IsNullOrEmpty(AsString(current)))
                {
                    builder.OpenElement(5, "option");
                    builder.AddAttribute(6, "value", "");
                    builder.AddAttribute(7, "disabled", true);
                    builder.AddAttribute(8, "selected", true);
                    builder.AddContent(9, "Select…");
                    builder.CloseElement();
                }
                var idx = 10;
                foreach (var (val, label) in field.Options ?? Array.Empty<(string, string)>())
                {
                    builder.OpenElement(idx++, "option");
                    builder.AddAttribute(idx++, "value", val);
                    builder.AddAttribute(idx++, "selected", val == AsString(current));
                    builder.AddContent(idx++, label);
                    builder.CloseElement();
                }
                builder.CloseElement();
                break;
            }
            default: // Text
            {
                builder.OpenElement(0, "input");
                builder.AddAttribute(1, "type", "text");
                builder.AddAttribute(2, "class", InputClass);
                builder.AddAttribute(3, "value", AsString(current));
                builder.AddAttribute(4, "placeholder", "Value");
                builder.AddAttribute(5, "aria-label", "Value");
                builder.AddAttribute(6, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e => await SetValue(rule, isSecond, e.Value?.ToString())));
                builder.CloseElement();
                break;
            }
        }
    };

    // Splits a stored comma-joined value into the set of currently-selected values, matching the
    // expression compiler's Split(',', RemoveEmptyEntries | TrimEntries) in QueryBuilderSerialization.
    private static IReadOnlyCollection<string> SelectedValues(QueryRule rule) =>
        (rule.Value?.ToString() ?? "")
            .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);

    // Value editor for the multi-value "in"/"notIn" operators. For Select fields this renders a
    // checkbox per option and stores the selected values as a comma-joined string (preserving option
    // order) so the compiler's OR/AND-of-equals set works. Non-Select fields fall back to a single
    // comma-separated text input.
    private RenderFragment RenderMultiValueEditor(QueryField field, QueryRule rule) => builder =>
    {
        if (field.Type == QueryFieldType.Select && field.Options is { Count: > 0 } options)
        {
            var selected = new HashSet<string>(SelectedValues(rule));
            builder.OpenElement(0, "div");
            builder.AddAttribute(1, "class", "flex flex-wrap items-center gap-x-3 gap-y-1");
            builder.AddAttribute(2, "role", "group");
            builder.AddAttribute(3, "aria-label", "Values");
            var seq = 4;
            foreach (var (val, label) in options)
            {
                var optionValue = val;
                var isChecked = selected.Contains(optionValue);
                builder.OpenElement(seq++, "label");
                builder.AddAttribute(seq++, "class", "inline-flex items-center gap-1.5 text-sm text-foreground");
                builder.OpenElement(seq++, "input");
                builder.AddAttribute(seq++, "type", "checkbox");
                builder.AddAttribute(seq++, "class", "h-4 w-4 rounded border-input accent-primary");
                builder.AddAttribute(seq++, "checked", isChecked);
                builder.AddAttribute(seq++, "aria-label", label);
                builder.AddAttribute(seq++, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e =>
                        {
                            var nowChecked = e.Value is bool b && b;
                            var current = new HashSet<string>(SelectedValues(rule));
                            if (nowChecked) current.Add(optionValue); else current.Remove(optionValue);
                            // Re-emit in declared option order so output is stable.
                            var joined = string.Join(",", options.Where(o => current.Contains(o.Value)).Select(o => o.Value));
                            await SetValue(rule, isSecond: false, joined);
                        }));
                builder.CloseElement();
                builder.AddContent(seq++, label);
                builder.CloseElement();
            }
            builder.CloseElement();
        }
        else
        {
            // Fallback for non-Select fields configured with a custom "in"/"notIn" operator:
            // a single comma-separated text input.
            builder.OpenElement(0, "input");
            builder.AddAttribute(1, "type", "text");
            builder.AddAttribute(2, "class", InputClass);
            builder.AddAttribute(3, "value", AsString(rule.Value));
            builder.AddAttribute(4, "placeholder", "Comma-separated values");
            builder.AddAttribute(5, "aria-label", "Comma-separated values");
            builder.AddAttribute(6, "onchange",
                Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                    this, async e => await SetValue(rule, isSecond: false, e.Value?.ToString())));
            builder.CloseElement();
        }
    };
}

using System.Diagnostics.CodeAnalysis;
using System.Linq.Expressions;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace Lumeo;

/// <summary>Boolean combinator for a <see cref="QueryGroup"/>.</summary>
[JsonConverter(typeof(QueryCombinatorJsonConverter))]
public enum QueryCombinator
{
    And,
    Or
}

// Hand-written string<->enum converter (kept trivial and reflection-free) rather than the
// framework JsonStringEnumConverter, whose non-generic form isn't guaranteed trim-clean and
// whose generic form (JsonStringEnumConverter<TEnum>) isn't available on the net8.0 TFM this
// assembly also targets. Enum.TryParse<TEnum>/.ToString() with a closed, compile-time-known
// TEnum are trim-safe (#354).
internal sealed class QueryCombinatorJsonConverter : JsonConverter<QueryCombinator>
{
    public override QueryCombinator Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
    {
        // reader.GetString() throws InvalidOperationException (not JsonException) for a
        // non-string token such as {"combinator":0,...}. FromJson only catches JsonException,
        // so an InvalidOperationException would escape past its documented
        // return-null-on-parse-failure contract instead of being treated as an invalid query.
        // Reject non-string tokens with JsonException up front so every malformed shape takes
        // the same documented path (#364 review).
        if (reader.TokenType != JsonTokenType.String)
            throw new JsonException($"Invalid QueryCombinator token '{reader.TokenType}'; expected a string.");

        var s = reader.GetString();
        // FromJson is documented to return null on parse failure (catches JsonException).
        // Silently coercing an invalid/corrupted combinator to And would instead hand back
        // a *different* query than the one that was saved, so an unrecognized value must
        // fail the parse rather than default (#364 review).
        //
        // Enum.TryParse ALSO succeeds for a quoted numeric literal like "2" — it returns an
        // undefined QueryCombinator(2) rather than failing, because TryParse's numeric-string
        // fallback doesn't check membership. Enum.IsDefined closes that gap so a hand-edited
        // or corrupted "combinator":"2" takes the same parse-failure path as a bogus word
        // (#366 review).
        return Enum.TryParse<QueryCombinator>(s, ignoreCase: true, out var value) && Enum.IsDefined(value)
            ? value
            : throw new JsonException($"Invalid QueryCombinator value '{s}'.");
    }

    public override void Write(Utf8JsonWriter writer, QueryCombinator value, JsonSerializerOptions options)
        => writer.WriteStringValue(value.ToString());
}

// QueryRule.Value/Value2 are declared `object?` — a genuinely open slot a consumer can box
// anything into. Relying on System.Text.Json's built-in polymorphic `object` resolution (even
// with a reflection-based resolver chained after the source-gen context) proved unreliable in
// this exact combination (source-gen context + List<T> of a polymorphic base + an `object`
// member): it kept resolving strictly against the context's own closed type list regardless of
// what was chained after it. Handling the (small, well-known) set of leaf value shapes
// explicitly — the same string/double/bool the built-in editors produce, plus every other
// framework numeric type a consumer might reasonably box in directly — sidesteps type-info
// resolution for `object` entirely: no reflection, no chain, no resolver ambiguity (#354).
internal sealed class QueryValueJsonConverter : JsonConverter<object?>
{
    public override object? Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options) =>
        reader.TokenType switch
        {
            JsonTokenType.Null => null,
            JsonTokenType.True => true,
            JsonTokenType.False => false,
            JsonTokenType.String => reader.GetString(),
            JsonTokenType.Number => ReadNumber(ref reader),
            _ => throw new JsonException($"Unsupported QueryRule value token '{reader.TokenType}'."),
        };

    // GetDouble() alone rounds anything above 2^53 (long IDs) or high-precision decimals
    // (money amounts) before ToExpression ever sees them, silently corrupting the saved
    // value. Try the narrowest exact representation first — Int64 for whole numbers,
    // Decimal for fixed-point fractional values — and only fall back to Double for
    // magnitudes/precision neither can hold (e.g. very large exponents) (#364 review).
    private static object ReadNumber(ref Utf8JsonReader reader)
    {
        if (reader.TryGetInt64(out var l)) return l;
        if (reader.TryGetDecimal(out var m)) return m;
        double d;
        try
        {
            d = reader.GetDouble();
        }
        catch (FormatException ex)
        {
            // Historically GetDouble() could throw FormatException for a literal outside even
            // Double's range; wrap it so every malformed numeric literal takes the same
            // documented (return-null-on-parse-failure) path regardless of BCL version (#366 review).
            throw new JsonException($"QueryRule value token is out of range for Int64/Decimal/Double.", ex);
        }

        // On current runtimes GetDouble() does NOT throw for an exponent/digit-count overflow
        // (e.g. a corrupted/hand-edited query with a 1e400 literal) — it silently clamps to
        // +/-Infinity instead. Infinity isn't valid JSON (WriteNumberValue throws ArgumentException
        // for it), so letting it through here would rehydrate a QueryRule.Value that ToExpression
        // can use for a comparison but ToJson can never persist again — silent corruption of the
        // saved query rather than the documented graceful parse failure. Reject it explicitly so
        // the oversized literal takes the same JsonException -> FromJson-returns-null path as
        // every other malformed numeric shape (#366 review).
        if (double.IsInfinity(d))
            throw new JsonException($"QueryRule value token is out of range for Int64/Decimal/Double.");

        return d;
    }

    public override void Write(Utf8JsonWriter writer, object? value, JsonSerializerOptions options)
    {
        switch (value)
        {
            case null: writer.WriteNullValue(); break;
            case string s: writer.WriteStringValue(s); break;
            case bool b: writer.WriteBooleanValue(b); break;
            // DateOnly/DateTime.ToString() is culture-sensitive (e.g. "12.07.2026" under
            // de-DE), but ConvertValue parses the reloaded string back with
            // CultureInfo.InvariantCulture. Under a non-invariant culture that mismatch
            // makes FromJson -> ToExpression fail to reload the query or compare against
            // the wrong date. Round-trip format ("O") is both invariant and exactly what
            // DateOnly/DateTime.Parse(..., InvariantCulture) expects (#364 review).
            case DateOnly dOnly: writer.WriteStringValue(dOnly.ToString("O", System.Globalization.CultureInfo.InvariantCulture)); break;
            case DateTime dt: writer.WriteStringValue(dt.ToString("O", System.Globalization.CultureInfo.InvariantCulture)); break;
            // Guid has no natural JSON number/bool shape; write it the same way ConvertValue
            // reads it back (Guid.Parse(s) from a plain string) so it round-trips (#366 review).
            case Guid g: writer.WriteStringValue(g); break;
            // MUST be checked before the numeric dispatch below: Type.GetTypeCode(enumType)
            // returns the enum's UNDERLYING integral TypeCode (e.g. TypeCode.Int32), so without
            // this guard an enum value would fall into WriteNumeric and be written as a raw
            // number — which ConvertValue's Enum.Parse(targetType, s) on reload cannot consume,
            // since it only ever receives a string (#366 review).
            case Enum e: writer.WriteStringValue(e.ToString()); break;
            default:
                WriteNumeric(writer, value);
                break;
        }
    }

    // Root fix for the recurring "one more boxed type isn't handled" review finding (three
    // consecutive rounds: custom non-scalar objects, then unsigned integrals, then enum/Guid
    // above): rather than growing an ad hoc `case long l: ... case short sh: ...` list one type
    // at a time, dispatch on Type.GetTypeCode, which has a CLOSED, fixed set of members for the
    // BCL's numeric primitives. Every numeric TypeCode (Byte/SByte/Int16/UInt16/Int32/UInt32/
    // Int64/UInt64/Single/Double/Decimal) is covered in this one switch, so there is no
    // "forgot a case" surface left for a fourth round to find (#366 review, root-cause).
    private static void WriteNumeric(Utf8JsonWriter writer, object value)
    {
        switch (Type.GetTypeCode(value.GetType()))
        {
            // byte/sbyte/short/ushort have no dedicated WriteNumberValue overload; they widen
            // implicitly to int, which does.
            case TypeCode.Byte: writer.WriteNumberValue((byte)value); break;
            case TypeCode.SByte: writer.WriteNumberValue((sbyte)value); break;
            case TypeCode.Int16: writer.WriteNumberValue((short)value); break;
            case TypeCode.UInt16: writer.WriteNumberValue((ushort)value); break;
            case TypeCode.Int32: writer.WriteNumberValue((int)value); break;
            case TypeCode.UInt32: writer.WriteNumberValue((uint)value); break;
            case TypeCode.Int64: writer.WriteNumberValue((long)value); break;
            case TypeCode.UInt64: writer.WriteNumberValue((ulong)value); break;
            case TypeCode.Decimal: writer.WriteNumberValue((decimal)value); break;
            case TypeCode.Single:
                var f = (float)value;
                // WriteNumberValue throws ArgumentException (not JsonException) for NaN/
                // Infinity — a caller boxing float.NaN directly (not read from JSON, since
                // ReadNumber already rejects an Infinity-clamped literal) would otherwise
                // escape ToJson's documented failure contract. Reject up front instead (#366
                // review — same reasoning as ReadNumber's IsInfinity guard, mirrored for Write).
                if (float.IsNaN(f) || float.IsInfinity(f)) throw NotFinite(value);
                // Widen to double before writing rather than writing at float's own (lower)
                // precision: ReadNumber's fallback numeric path only ever reconstructs a
                // double (there is no "read back as float" branch), so a float-precision
                // literal reparses to a DIFFERENT double than the exact widened value —
                // enough drift near float.MaxValue to round the reloaded double to
                // +/-Infinity. Writing the exact widened double makes that reparse bit-exact
                // (caught by the round-trip fuzz matrix, #366 review — root-cause fix, not
                // one of the four filed findings, but the same failure class).
                writer.WriteNumberValue((double)f);
                break;
            case TypeCode.Double:
                var d = (double)value;
                if (double.IsNaN(d) || double.IsInfinity(d)) throw NotFinite(value);
                writer.WriteNumberValue(d);
                break;
            default:
                // A ToString() fallback here would silently CORRUPT the saved query for any
                // custom ValueEditorTemplate that boxes a non-scalar shape into Value/Value2
                // (e.g. a string[] becomes the literal text "System.String[]", losing the data
                // with no way to tell from the written JSON that anything went wrong). Reject
                // instead of guessing: throw the documented JsonException so ToJson fails loudly
                // and the caller finds out immediately, rather than persisting an unrecoverable
                // query it will fail to explain later (#366 review). Structured values that DO
                // need to round-trip should be normalized to one of the scalar shapes above by
                // the consumer's ValueEditorTemplate before assigning Value/Value2.
                throw new JsonException(
                    $"QueryRule value of type '{value.GetType()}' is not supported by the trim-safe " +
                    "QueryValueJsonConverter (only string/bool/numeric/enum/Guid/DateOnly/DateTime are). " +
                    "Normalize the value to one of those shapes before assigning it to Value/Value2.");
        }
    }

    private static JsonException NotFinite(object value) => new(
        $"QueryRule value '{value}' is not a finite number; NaN/Infinity cannot be persisted as JSON.");
}

/// <summary>The data type of a <see cref="QueryField"/>. Drives the default operator
/// set and the built-in value editor rendered for a rule.</summary>
public enum QueryFieldType
{
    Text,
    Number,
    Date,
    Boolean,
    Select
}

/// <summary>
/// A field definition the consumer provides to <see cref="QueryBuilder"/>.
/// <see cref="Name"/> is the stable key written into produced rules;
/// <see cref="Label"/> is the human-facing text shown in the field picker.
/// </summary>
public sealed class QueryField
{
    /// <summary>Stable key written to <see cref="QueryRule.Field"/>. Required.</summary>
    public string Name { get; set; } = "";

    /// <summary>Human-facing label shown in the field picker. Falls back to <see cref="Name"/>.</summary>
    public string? Label { get; set; }

    /// <summary>The field's data type. Determines the default operator set and value editor.</summary>
    public QueryFieldType Type { get; set; } = QueryFieldType.Text;

    /// <summary>The operator keys allowed for this field. When <c>null</c>, the default
    /// set for <see cref="Type"/> is used (see <see cref="QueryBuilderOperators.DefaultsFor"/>).</summary>
    public IReadOnlyList<string>? Operators { get; set; }

    /// <summary>Options shown when <see cref="Type"/> is <see cref="QueryFieldType.Select"/>.
    /// Each tuple is <c>(Value, Label)</c>.</summary>
    public IReadOnlyList<(string Value, string Label)>? Options { get; set; }

    /// <summary>The display label — <see cref="Label"/> when set, otherwise <see cref="Name"/>.</summary>
    [JsonIgnore]
    public string DisplayLabel => string.IsNullOrEmpty(Label) ? Name : Label;

    /// <summary>The effective operator keys for this field.</summary>
    public IReadOnlyList<string> EffectiveOperators =>
        Operators is { Count: > 0 } ? Operators : QueryBuilderOperators.DefaultsFor(Type);
}

/// <summary>Base type for a node in a query tree — either a <see cref="QueryRule"/>
/// (a leaf condition) or a <see cref="QueryGroup"/> (a combinator with children).</summary>
[JsonDerivedType(typeof(QueryRule), "rule")]
[JsonDerivedType(typeof(QueryGroup), "group")]
public abstract class QueryNode
{
}

/// <summary>A single leaf condition: a field, an operator, and a comparison value.</summary>
public sealed class QueryRule : QueryNode
{
    /// <summary>The <see cref="QueryField.Name"/> this rule targets.</summary>
    [JsonPropertyName("field")] public string Field { get; set; } = "";

    /// <summary>One of the field's allowed operator keys.</summary>
    [JsonPropertyName("operator")] public string Operator { get; set; } = "";

    /// <summary>The comparison value. Type depends on the field; for "between"-style
    /// operators this holds the lower bound and <see cref="Value2"/> holds the upper.</summary>
    [JsonPropertyName("value"), JsonConverter(typeof(QueryValueJsonConverter))]
    public object? Value { get; set; }

    /// <summary>The second comparison value, used only by range operators ("between").</summary>
    [JsonPropertyName("value2"), JsonConverter(typeof(QueryValueJsonConverter))]
    public object? Value2 { get; set; }
}

/// <summary>A group: a <see cref="QueryCombinator"/> applied across a list of child
